            ],
            'roadhouse-cafe-pokhara' => [
                'description' => '<p>Roadhouse Café Pokhara is the city\'s original American-style diner — a high-energy, music-filled venue that has been the after-trek celebration destination of choice since its founding. With a wood-and-brick interior, neon signs, vintage rock posters, and a jukebox that plays classic rock, country, and blues, Roadhouse creates an atmosphere that feels a world away from the Himalayas and yet entirely at home in it.</p><p>The menu is unapologetically American: double cheeseburgers with hand-cut fries, BBQ ribs with coleslaw, loaded potato skins, chilli con carne, and a dessert menu anchored by the legendary house brownie with vanilla ice cream. The bar carries an exceptional selection of American whiskey and craft spirits.</p>',
                'opening_hours' => '11:00 AM – 11:30 PM (open daily)',
                'features' => $this->features(['American-style diner', 'Classic rock & blues atmosphere', 'BBQ ribs & burgers', 'Hand-cut fries', 'American whiskey bar', 'Craft spirits selection', 'Live music weekends', 'Happy hour 5–7 PM', 'Group bookings', 'Free Wi-Fi']),
