            'moondance-restaurant-bar' => [
                'description' => '<p>Moondance Restaurant & Bar is a romantic Lakeside dining destination that has perfected the formula of great food, warm lighting, and an atmosphere that makes every meal feel like a celebration. The open terrace overlooks a quiet stretch of the Lakeside promenade, ideal for evenings when the stars reflect in Phewa Lake.</p><p>The menu is an eclectic world tour: Mediterranean mezze, Japanese ramen, Mexican tacos, and Nepali mountain cheeses alongside perfectly executed steaks and fresh-caught trout. The cocktail list features house-infused spirits and fresh mountain herbs. Live acoustic guitar performances run Wednesday and Saturday evenings.</p>',
                'opening_hours' => '11:00 AM – 11:00 PM (open daily)',
                'features' => $this->features(['Romantic lakeside terrace', 'Live acoustic guitar Wed & Sat', 'Eclectic world cuisine', 'Fresh local trout', 'Creative cocktail list', 'House-infused spirits', 'Full bar & wine list', 'Vegan-friendly options', 'Reservation recommended', 'Free Wi-Fi']),
