            'tibetan-yak' => [
                'description' => '<p>Tibetan Yak is Pokhara\'s most authentic Tibetan restaurant — a warm, incense-scented space decorated with traditional thangka paintings, butter lamps, and hand-carved wooden furniture that creates the atmosphere of a traditional Tibetan household. The restaurant has been run by a family of Tibetan refugees for over 25 years with pride and cultural integrity.</p><p>The menu centres on the hearty, nourishing food that sustained Tibetan communities across the high plateau: thenthuk (flat hand-torn noodle soup), shyakpa (meat and vegetable stew), sha balep (meat-filled flatbread), and an exceptional Tibetan hot pot available for groups of four or more. Yak butter tea and chang (fermented barley beer) are the traditional drink accompaniments.</p>',
                'opening_hours' => '10:00 AM – 9:30 PM (open daily)',
                'features' => $this->features(['Authentic Tibetan family restaurant', 'Thenthuk & shyakpa specialties', 'Sha balep (meat flatbread)', 'Tibetan hot pot (4+ guests)', 'Yak butter tea', 'Chang fermented beer', 'Thangka art & butter lamps', 'No pork served', 'Vegetarian Tibetan menu', 'Cultural atmosphere']),
